INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Apnealink Air', 'Diagnóstico del Sueño', 50290.0, 50290.0, 'ApneaLink Air Dispositivo de diagnóstico portátil utilizado en el estudio del sueño para evaluar trastornos respiratorios como la apnea obstructiva...', 'ApneaLink Air Dispositivo de diagnóstico portátil utilizado en el estudio del sueño para evaluar trastornos respiratorios como la apnea obstructiva del sueño (AOS) y la hipopnea. Este sistema permite monitorear los patrones de sueño y evaluar los trastornos respiratorios durante la noche, proporcionando datos cruciales para el diagnóstico médico.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-17-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-17-600x600.jpg'], true, 'apnealink-air', 0, 0, '[]'::jsonb, 'ApneaLink Air', 'ApneaLink Air Portable diagnostic device used in sleep studies to evaluate respiratory disorders such as obstructive sleep apnea (OSA) and hypopnea...', 'ApneaLink Air Portable diagnostic device used in sleep studies to evaluate respiratory disorders such as obstructive sleep apnea (OSA) and hypopnea. This system allows for the monitoring of sleep patterns and evaluation of respiratory disorders during the night, providing crucial data for medical diagnosis.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Airsense 10 Cpap Con Mascarilla P10 Dos Unidades De Cada Una', 'Terapia de Sueño', 22100.0, 22100.0, 'Equipo de presión fija ajustable de 4 a 20 cm. H2O. Se compone de dos unidades del dispositivo AirSense 10 y dos unidades de la mascarilla P10, dis...', 'Equipo de presión fija ajustable de 4 a 20 cm. H2O. Se compone de dos unidades del dispositivo AirSense 10 y dos unidades de la mascarilla P10, diseñado para ofrecer una solución completa y eficaz para el tratamiento de la apnea del sueño.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-30-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-30-600x600.jpg'], true, 'airsense-10-cpap-con-mascarilla-p10-dos-unidades-de-cada-una', 0, 0, '[]'::jsonb, 'AirSense 10 CPAP with P10 Mask Two Units of Each', 'Adjustable fixed pressure equipment from 4 to 20 cm H2O. It consists of two units of the AirSense 10 device and two units of the P10 mask, designed...', 'Adjustable fixed pressure equipment from 4 to 20 cm H2O. It consists of two units of the AirSense 10 device and two units of the P10 mask, designed to offer a complete and effective solution for the treatment of sleep apnea.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Adaptador Para Filtro Espirometria', 'Accesorios Médicos', 1480.0, 1480.0, 'Es un dispositivo diseñado para conectar filtros bacterianos y virales a equipos de espirometría. Estos filtros son esenciales para garantizar la p...', 'Es un dispositivo diseñado para conectar filtros bacterianos y virales a equipos de espirometría. Estos filtros son esenciales para garantizar la precisión de las mediciones y para proteger tanto al paciente como al equipo de posibles contaminantes. Estos filtros son cruciales para evitar la contaminación cruzada y proteger tanto al paciente como al equipo médico de la inhalación de microorganismos durante las pruebas respiratorias.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-09-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-09-600x600.jpg'], true, 'adaptador-para-filtro-espirometria', 0, 0, '[]'::jsonb, 'Spirometry Filter Adapter', 'It is a device designed to connect bacterial and viral filters to spirometry equipment. These filters are essential to ensure the accuracy of measu...', 'It is a device designed to connect bacterial and viral filters to spirometry equipment. These filters are essential to ensure the accuracy of measurements and to protect both the patient and the equipment from potential contaminants. These filters are crucial to avoid cross-contamination and protect both the patient and the medical equipment from inhaling microorganisms during respiratory tests.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Aircurve 10 V Auto', 'Terapia de Sueño', 31256.0, 31256.0, 'Dispositivo de terapia de presión positiva en las vías respiratorias (CPAP) fabricado por ResMed. Este dispositivo está diseñado para proporcionar ...', 'Dispositivo de terapia de presión positiva en las vías respiratorias (CPAP) fabricado por ResMed. Este dispositivo está diseñado para proporcionar soporte respiratorio tanto en modos de ventilación controlada como en modos de presión positiva automática, adaptándose de manera dinámica a las necesidades respiratorias del paciente durante el sueño.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-10-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-10-600x600.jpg'], true, 'aircurve-10-v-auto', 0, 0, '[]'::jsonb, 'AirCurve 10 V Auto', 'Positive airway pressure (CPAP) therapy device manufactured by ResMed. This device is designed to provide respiratory support in both controlled ve...', 'Positive airway pressure (CPAP) therapy device manufactured by ResMed. This device is designed to provide respiratory support in both controlled ventilation modes and automatic positive pressure modes, dynamically adapting to the patient''s respiratory needs during sleep.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Almohada Cpapmax 2 0', 'Accesorios de Sueño', 2668.0, 2668.0, 'Almohada diseñada para personas que utilizan dispositivos CPAP (presión positiva continua en las vías respiratorias) para el tratamiento de la apne...', 'Almohada diseñada para personas que utilizan dispositivos CPAP (presión positiva continua en las vías respiratorias) para el tratamiento de la apnea del sueño u otros trastornos respiratorios durante la noche.  Estas almohadas están diseñadas para ofrecer comodidad y soporte, teniendo en cuenta las necesidades únicas de quienes usan mascarillas CPAP para tratar la apnea del sueño y otros trastornos respiratorios.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-13-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-13-600x600.jpg'], true, 'almohada-cpapmax-2-0', 0, 0, '[]'::jsonb, 'CPAPmax 2.0 Pillow', 'Pillow designed for people who use CPAP devices (continuous positive airway pressure) for the treatment of sleep apnea or other respiratory disorde...', 'Pillow designed for people who use CPAP devices (continuous positive airway pressure) for the treatment of sleep apnea or other respiratory disorders during the night. These pillows are designed to offer comfort and support, taking into account the unique needs of those who use CPAP masks to treat sleep apnea and other respiratory disorders.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Analizador De Quimica Clinica', 'Equipos de Laboratorio', 625900.0, 625900.0, 'Av Periférico Sur 4829, Piso 2, Col. Parque del Pedregal, Tlalpan, Ciudad de México, CP 14010', 'Av Periférico Sur 4829, Piso 2, Col. Parque del Pedregal, Tlalpan, Ciudad de México, CP 14010', 'https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-39-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-39-600x600.jpg'], true, 'analizador-de-quimica-clinica', 0, 0, '[]'::jsonb, 'Clinical Chemistry Analyzer', 'Av Periférico Sur 4829, 2nd Floor, Col. Parque del Pedregal, Tlalpan, Mexico City, CP 14010.', 'Av Periférico Sur 4829, 2nd Floor, Col. Parque del Pedregal, Tlalpan, Mexico City, CP 14010.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('B8 Incubadora Neonatal', 'Cuidado Neonatal', 290500.0, 290500.0, 'Pantalla táctil TFT de 12,1″. Control de temperatura (modo aire/bebé). Una (1) sonda de temperatura (temperatura de la piel). Control de humedad. P...', 'Pantalla táctil TFT de 12,1″. Control de temperatura (modo aire/bebé). Una (1) sonda de temperatura (temperatura de la piel). Control de humedad. Pared de doble capa diseñada. Puertas amortiguadoras. Elevación de cama electrónica. Inclinación electrónica de la cama. Un (1) cajón de almacenamiento. Un (1) colchón de PU, 396*622*20 mm. Bandeja de rayos X. Bandeja. Monitor modular C31 (C31 configurado por separado en SAP. Especifíquelo en orden). Impresora para monitor modular.', 'https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-42-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-42-600x600.jpg'], true, 'b8-incubadora-neonatal', 0, 0, '[]'::jsonb, 'B8 Neonatal Incubator', '12.1" TFT touch screen. Temperature control (air/baby mode). One (1) temperature probe (skin temperature). Humidity control. Double-layered wall de...', '12.1" TFT touch screen. Temperature control (air/baby mode). One (1) temperature probe (skin temperature). Humidity control. Double-layered wall design. Dampening doors. Electronic bed lift. Electronic bed tilt. One (1) storage drawer. One (1) PU mattress, 396*622*20 mm. X-ray tray. Tray. C31 modular monitor (C31 configured separately in SAP. Specify in order). Printer for modular monitor.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Bomba De Infusion Comen M260', 'Cuidado Crítico', 26450.0, 26450.0, 'Múltiples modos de funcionamiento: incluye modos de infusión básicos, como modo de velocidad, modo de tiempo y modo de peso; modos de infusión avan...', 'Múltiples modos de funcionamiento: incluye modos de infusión básicos, como modo de velocidad, modo de tiempo y modo de peso; modos de infusión avanzados, como modo intermitente, modo de rampa, modo de secuencia, modo micro, modo de primera dosis (TIVA), modo de dosis-tiempo y modo de visualización adicional: modo nocturno', 'https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-34-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-34-600x600.jpg'], true, 'bomba-de-infusion-comen-m260', 0, 0, '[]'::jsonb, 'Comen M260 Infusion Pump', 'Multiple operating modes: includes basic infusion modes, such as rate mode, time mode, and weight mode; advanced infusion modes, such as intermitte...', 'Multiple operating modes: includes basic infusion modes, such as rate mode, time mode, and weight mode; advanced infusion modes, such as intermittent mode, ramp mode, sequence mode, micro mode, first dose mode (TIVA), dose-time mode, and additional display mode: night mode.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Bomba De Infusion Comen Me660', 'Cuidado Crítico', 28900.0, 28900.0, 'Múltiples modos de trabajo: Presenta modos de infusión básicos que incluyen modo de velocidad, modo de tiempo, modo de peso; modos de infusión avan...', 'Múltiples modos de trabajo: Presenta modos de infusión básicos que incluyen modo de velocidad, modo de tiempo, modo de peso; modos de infusión avanzados como modo de goteo, modo intermitente, modo de rampa, modo de secuencia, modo micro, modo de primera dosis (TIVA), modo de dosis-tiempo y modo de visualización adicional: modo nocturno', 'https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-33-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-33-600x600.jpg'], true, 'bomba-de-infusion-comen-me660', 0, 0, '[]'::jsonb, 'Comen ME660 Infusion Pump', 'Multiple working modes: Features basic infusion modes including rate mode, time mode, weight mode; advanced infusion modes such as drip mode, inter...', 'Multiple working modes: Features basic infusion modes including rate mode, time mode, weight mode; advanced infusion modes such as drip mode, intermittent mode, ramp mode, sequence mode, micro mode, first dose mode (TIVA), dose-time mode, and additional display mode: night mode.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Bomba De Infusion M500', 'Cuidado Crítico', 40900.0, 40900.0, 'Cascada de dos canales. Pantalla de 6,2 pulgadas con inclinación de 0 a 45 grados, operación de pantalla táctil, visualización numérica y la infusi...', 'Cascada de dos canales. Pantalla de 6,2 pulgadas con inclinación de 0 a 45 grados, operación de pantalla táctil, visualización numérica y la infusión única continua máxima es de 120 ml de solución de fármaco. Múltiples modos de trabajo: incluye modo de velocidad, modo de tiempo, modo de peso, modo de intervalo, modo trapecio, modo secuencial, modo rampa, modo micro, modo TIVA, modo de primera dosis y modo nocturno. Abrazadera para poste.', 'https://prime-health.mx/wp-content/uploads/2024/08/19-600x512.webp', ARRAY['https://prime-health.mx/wp-content/uploads/2024/08/19-600x512.webp'], true, 'bomba-de-infusion-m500', 0, 0, '[]'::jsonb, 'M500 Infusion Pump', 'Two-channel cascade. 6.2-inch screen with 0 to 45-degree tilt, touch screen operation, numerical display, and the maximum single continuous infusio...', 'Two-channel cascade. 6.2-inch screen with 0 to 45-degree tilt, touch screen operation, numerical display, and the maximum single continuous infusion is 120 ml of drug solution. Multiple working modes: includes rate mode, time mode, weight mode, interval mode, trapezoid mode, sequential mode, ramp mode, micro mode, TIVA mode, first dose mode, and night mode. Pole clamp.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Boquillas Pediatricas', 'Consumibles', 470.0, 470.0, 'Son accesorios utilizados en espirometría para realizar pruebas de función pulmonar en niños y bebés. Estas boquillas están diseñadas específicamen...', 'Son accesorios utilizados en espirometría para realizar pruebas de función pulmonar en niños y bebés. Estas boquillas están diseñadas específicamente para adaptarse al tamaño y a las necesidades respiratorias de los pacientes pediátricos, asegurando mediciones precisas y cómodas durante las pruebas.Estas boquillas permiten que los niños respiren de manera cómoda y adecuada durante las pruebas de función pulmonar, lo que es crucial para obtener mediciones precisas.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-07-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-07-600x600.jpg'], true, 'boquillas-pediatricas', 0, 0, '[]'::jsonb, 'Pediatric Mouthpieces', 'These are accessories used in spirometry to perform lung function tests in children and babies. These mouthpieces are specifically designed to adap...', 'These are accessories used in spirometry to perform lung function tests in children and babies. These mouthpieces are specifically designed to adapt to the size and respiratory needs of pediatric patients, ensuring accurate and comfortable measurements during testing. These mouthpieces allow children to breathe comfortably and properly during lung function tests, which is crucial for obtaining accurate measurements.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Canula Nasal Apnealink', 'Accesorios de Sueño', 350.0, 350.0, 'Accesorio utilizado con el sistema ApneaLink de ResMed, un dispositivo portátil para la detección y monitoreo de la apnea del sueño. Esta cánula na...', 'Accesorio utilizado con el sistema ApneaLink de ResMed, un dispositivo portátil para la detección y monitoreo de la apnea del sueño. Esta cánula nasal está diseñada para proporcionar una medición precisa del flujo de aire durante el sueño, facilitando la evaluación de los trastornos respiratorios del sueño en el entorno domiciliario.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-19-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-19-600x600.jpg'], true, 'canula-nasal-apnealink', 0, 0, '[]'::jsonb, 'ApneaLink Nasal Cannula', 'Accessory used with ResMed''s ApneaLink system, a portable device for the detection and monitoring of sleep apnea. This nasal cannula is designed to...', 'Accessory used with ResMed''s ApneaLink system, a portable device for the detection and monitoring of sleep apnea. This nasal cannula is designed to provide an accurate measurement of airflow during sleep, facilitating the evaluation of sleep-disordered breathing in the home environment.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Circuito Para Airmini', 'Terapia de Sueño', 1360.0, 1360.0, 'El AirMini es un dispositivo de CPAP (presión positiva continua en las vías respiratorias) diseñado para ayudar a tratar la apnea del sueño y otros...', 'El AirMini es un dispositivo de CPAP (presión positiva continua en las vías respiratorias) diseñado para ayudar a tratar la apnea del sueño y otros trastornos respiratorios durante la noche. El circuito para AirMini, que se conecta al dispositivo', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-21-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-21-600x600.jpg'], true, 'circuito-para-airmini', 0, 0, '[]'::jsonb, 'Circuit for AirMini', 'The AirMini is a CPAP (continuous positive airway pressure) device designed to help treat sleep apnea and other respiratory disorders during the ni...', 'The AirMini is a CPAP (continuous positive airway pressure) device designed to help treat sleep apnea and other respiratory disorders during the night. The circuit for AirMini, which connects to the device.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Colposcopio Ci 100F', 'Ginecología', 275000.0, 275000.0, 'Vida de LED 50,000 hrs, 20% más iluminación, LED más blanca, halógeno más amarilla. 5 aumentos. brazo pantográfico, sistema Rulemanes, oculares de ...', 'Vida de LED 50,000 hrs, 20% más iluminación, LED más blanca, halógeno más amarilla. 5 aumentos. brazo pantográfico, sistema Rulemanes, oculares de visión 10X y gran angular de 25mm.', 'https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-38-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-38-600x600.jpg'], true, 'colposcopio-ci-100f', 0, 0, '[]'::jsonb, 'Colposcope Ci 100F', 'LED life 50,000 hrs, 20% more lighting, whiter LED, halogen is yellower. 5 magnifications. Pantographic arm, Ball bearing system, 10X vision eyepie...', 'LED life 50,000 hrs, 20% more lighting, whiter LED, halogen is yellower. 5 magnifications. Pantographic arm, Ball bearing system, 10X vision eyepieces, and 25mm wide angle.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Compresor De Aire Comen Vs 20', 'Equipos Hospitalarios', 110200.0, 110200.0, 'El manómetro está diseñado con un ángulo de inclinación de 60° para una fácil visualización. Súper silencioso con un nivel de ruido más bajo de has...', 'El manómetro está diseñado con un ángulo de inclinación de 60° para una fácil visualización. Súper silencioso con un nivel de ruido más bajo de hasta 45 dB.', 'https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-35-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-35-600x600.jpg'], true, 'compresor-de-aire-comen-vs-20', 0, 0, '[]'::jsonb, 'Comen Vs 20 Air Compressor', 'The pressure gauge is designed with a 60° tilt angle for easy viewing. Super quiet with a noise level as low as 45 dB.', 'The pressure gauge is designed with a 60° tilt angle for easy viewing. Super quiet with a noise level as low as 45 dB.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Concentrador Everflo Con Opi Y Pulso Oximetro Onyx Vantage 9590', 'Oxigenoterapia', 25020.0, 25020.0, 'Diseñado para uso en el hogar y en entornos clínicos. Es un conjunto de dispositivos médicos diseñado para proporcionar terapia de oxígeno de maner...', 'Diseñado para uso en el hogar y en entornos clínicos. Es un conjunto de dispositivos médicos diseñado para proporcionar terapia de oxígeno de manera eficiente y precisa, junto con la capacidad de monitorear de manera confiable la saturación de oxígeno en la sangre y la frecuencia del pulso.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-26-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-26-600x600.jpg'], true, 'concentrador-everflo-con-opi-y-pulso-oximetro-onyx-vantage-9590', 0, 0, '[]'::jsonb, 'Everflo Concentrator with OPI and Onyx Vantage 9590 Pulse Oximeter', 'Designed for use at home and in clinical settings. It is a set of medical devices designed to provide oxygen therapy efficiently and accurately, al...', 'Designed for use at home and in clinical settings. It is a set of medical devices designed to provide oxygen therapy efficiently and accurately, along with the ability to reliably monitor blood oxygen saturation and pulse rate.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Concentrador Inogen At Home', 'Oxigenoterapia', 40100.0, 40100.0, 'Con su diseño compacto y eficiente, proporciona un flujo de oxígeno de alto rendimiento mientras ahorra energía, ideal para pacientes que requieren...', 'Con su diseño compacto y eficiente, proporciona un flujo de oxígeno de alto rendimiento mientras ahorra energía, ideal para pacientes que requieren terapia de oxígeno a largo plazo. Este concentrador es conocido por su eficiencia energética, diseño compacto y facilidad de uso, lo que lo hace ideal para uso diario en el hogar.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-25-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-25-600x600.jpg'], true, 'concentrador-inogen-at-home', 0, 0, '[]'::jsonb, 'Inogen At Home Concentrator', 'With its compact and efficient design, it provides high-performance oxygen flow while saving energy, ideal for patients requiring long-term oxygen ...', 'With its compact and efficient design, it provides high-performance oxygen flow while saving energy, ideal for patients requiring long-term oxygen therapy. This concentrator is known for its energy efficiency, compact design, and ease of use, making it ideal for daily use at home.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Filtro Para Espirometria', 'Consumibles', 200.0, 200.0, 'Es un componente esencial utilizado en equipos de espirometría para proteger tanto al paciente como al Dispositivo de la inhalación de partículas y...', 'Es un componente esencial utilizado en equipos de espirometría para proteger tanto al paciente como al Dispositivo de la inhalación de partículas y microorganismos durante las pruebas respiratorias. Estos filtros cumplen varias funciones clave para garantizar la precisión de las mediciones y mantener un entorno clínico seguro y limpio.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-08-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-08-600x600.jpg'], true, 'filtro-para-espirometria', 0, 0, '[]'::jsonb, 'Spirometry Filter', 'It is an essential component used in spirometry equipment to protect both the patient and the device from inhaling particles and microorganisms dur...', 'It is an essential component used in spirometry equipment to protect both the patient and the device from inhaling particles and microorganisms during respiratory tests. These filters fulfill several key functions to ensure measurement accuracy and maintain a safe and clean clinical environment.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Filtros Astral', 'Consumibles', 2481.0, 2481.0, 'Estos filtros están diseñados para atrapar partículas como polvo, polen, bacterias y virus, ayudando a mantener un entorno respiratorio limpio y se...', 'Estos filtros están diseñados para atrapar partículas como polvo, polen, bacterias y virus, ayudando a mantener un entorno respiratorio limpio y seguro.son accesorios esenciales para los ventiladores Astral de ResMed, diseñados para garantizar un suministro de aire limpio y seguro a los pacientes que utilizan estos dispositivos de soporte respiratorio. Estos filtros ayudan a proteger tanto al paciente como al dispositivo de partículas y contaminantes presentes en el aire.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-20-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-20-600x600.jpg'], true, 'filtros-astral', 0, 0, '[]'::jsonb, 'Astral Filters', 'These filters are designed to trap particles such as dust, pollen, bacteria, and viruses, helping to maintain a clean and safe respiratory environm...', 'These filters are designed to trap particles such as dust, pollen, bacteria, and viruses, helping to maintain a clean and safe respiratory environment. They are essential accessories for ResMed''s Astral ventilators, designed to ensure a clean and safe air supply to patients using these respiratory support devices. These filters help protect both the patient and the device from particles and contaminants present in the air.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Filtros S8', 'Consumibles', 180.0, 180.0, 'Estos filtros cumplen una función importante en la limpieza y purificación del aire que circula dentro del dispositivo CPAP.Estos filtros juegan un...', 'Estos filtros cumplen una función importante en la limpieza y purificación del aire que circula dentro del dispositivo CPAP.Estos filtros juegan un papel crucial en la purificación del aire que ingresa al dispositivo, protegiendo tanto la máquina como al usuario de la inhalación de partículas de polvo y otros contaminantes presentes en el entorno.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-15-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-15-600x600.jpg'], true, 'filtros-s8', 0, 0, '[]'::jsonb, 'S8 Filters', 'These filters play an important role in cleaning and purifying the air that circulates within the CPAP device. These filters play a crucial role in...', 'These filters play an important role in cleaning and purifying the air that circulates within the CPAP device. These filters play a crucial role in purifying the air that enters the device, protecting both the machine and the user from inhaling dust particles and other contaminants present in the environment.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Gecko Pad', 'Accesorios de Sueño', 764.0, 764.0, 'Es un accesorio diseñado para mejorar la comodidad y el sellado de las mascarillas nasales en los dispositivos de terapia de CPAP.Este producto, fa...', 'Es un accesorio diseñado para mejorar la comodidad y el sellado de las mascarillas nasales en los dispositivos de terapia de CPAP.Este producto, fabricado por ResMed, está específicamente diseñado para utilizarse con mascarillas nasales y oronasales de la serie ResMed Mirage™, incluyendo modelos como la Mirage Activa™ LT y la Mirage Quattro™.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-14-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-14-600x600.jpg'], true, 'gecko-pad', 0, 0, '[]'::jsonb, 'Gecko Pad', 'It is an accessory designed to improve the comfort and sealing of nasal masks in CPAP therapy devices. This product, manufactured by ResMed, is spe...', 'It is an accessory designed to improve the comfort and sealing of nasal masks in CPAP therapy devices. This product, manufactured by ResMed, is specifically designed for use with ResMed Mirage™ series nasal and oronasal masks, including models such as the Mirage Activa™ LT and the Mirage Quattro™.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Humidificador Activo', 'Cuidado Respiratorio', 46230.0, 46230.0, 'Marca Neptune. Dispositivo diseñado para mantener un nivel óptimo de humedad en el aire, mejorando la calidad del ambiente en espacios interiores. ...', 'Marca Neptune. Dispositivo diseñado para mantener un nivel óptimo de humedad en el aire, mejorando la calidad del ambiente en espacios interiores. Este humidificador es especialmente útil para personas que sufren de sequedad en las vías respiratorias, piel seca, o para aquellos que buscan mejorar el confort general de su entorno.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-29-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-29-600x600.jpg'], true, 'humidificador-activo', 0, 0, '[]'::jsonb, 'Active Humidifier', 'Neptune brand. Device designed to maintain an optimal humidity level in the air, improving environmental quality in indoor spaces. This humidifier ...', 'Neptune brand. Device designed to maintain an optimal humidity level in the air, improving environmental quality in indoor spaces. This humidifier is especially useful for people suffering from dry airways, dry skin, or those looking to improve the general comfort of their environment.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Humidificador Respiratorio Comen Nf5', 'Cuidado Respiratorio', 80500.0, 80500.0, 'Mezclador electrónico de aire y oxígeno, función de ventilación rápida de oxígeno, función de temporizador', 'Mezclador electrónico de aire y oxígeno, función de ventilación rápida de oxígeno, función de temporizador', 'https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-36-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-36-600x600.jpg'], true, 'humidificador-respiratorio-comen-nf5', 0, 0, '[]'::jsonb, 'Comen NF5 Respiratory Humidifier', 'Electronic air and oxygen mixer, rapid oxygen ventilation function, timer function.', 'Electronic air and oxygen mixer, rapid oxygen ventilation function, timer function.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Humidificador Termico Tr917 Evolution Servocontrolado', 'Cuidado Respiratorio', 36480.0, 36480.0, 'Con características de última generación, el TR917 Evolution es ideal para unidades de cuidados intensivos y otras aplicaciones críticas donde la h...', 'Con características de última generación, el TR917 Evolution es ideal para unidades de cuidados intensivos y otras aplicaciones críticas donde la humedad precisa es esencial para la comodidad y recuperación del paciente.Es un dispositivo avanzado diseñado para proporcionar un control preciso de la humedad en ambientes específicos. Este tipo de humidificador es ideal para aplicaciones en el ámbito médico, laboratorios, y otros entornos donde se requiere una regulación exacta de la humedad.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-28-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-28-600x600.jpg'], true, 'humidificador-termico-tr917-evolution-servocontrolado', 0, 0, '[]'::jsonb, 'TR917 Evolution Servo-Controlled Thermal Humidifier', 'With state-of-the-art features, the TR917 Evolution is ideal for intensive care units and other critical applications where precise humidity is ess...', 'With state-of-the-art features, the TR917 Evolution is ideal for intensive care units and other critical applications where precise humidity is essential for patient comfort and recovery. It is an advanced device designed to provide precise control of humidity in specific environments. This type of humidifier is ideal for applications in the medical field, laboratories, and other environments where exact regulation of humidity is required.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Humidificador Tr 517 Para Ventiladores 5 Niveles De Temperatura', 'Cuidado Respiratorio', 19735.0, 19735.0, 'Ofrece cinco niveles de temperatura ajustables, garantizando una humidificación óptima y confortable para los pacientes en entornos críticos. Ideal...', 'Ofrece cinco niveles de temperatura ajustables, garantizando una humidificación óptima y confortable para los pacientes en entornos críticos. Ideal para unidades de cuidados intensivos y otros escenarios médicos, el TR-517 asegura una humidificación precisa y constante.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-27-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-27-600x600.jpg'], true, 'humidificador-tr-517-para-ventiladores-5-niveles-de-temperatura', 0, 0, '[]'::jsonb, 'TR 517 Humidifier for Ventilators with 5 Temperature Levels', 'Offers five adjustable temperature levels, ensuring optimal and comfortable humidification for patients in critical settings. Ideal for intensive c...', 'Offers five adjustable temperature levels, ensuring optimal and comfortable humidification for patients in critical settings. Ideal for intensive care units and other medical scenarios, the TR-517 ensures precise and constant humidification.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Humidx', 'Accesorios de Sueño', 730.0, 730.0, 'HumidX es un componente diseñado específicamente para los dispositivos de terapia de CPAP de ResMed, como el AirMini, que ofrece humidificación int...', 'HumidX es un componente diseñado específicamente para los dispositivos de terapia de CPAP de ResMed, como el AirMini, que ofrece humidificación integrada para mejorar la comodidad respiratoria durante el sueño. Este pequeño intercambiador de calor y humedad se adapta directamente dentro del conector de la mascarilla, ofreciendo beneficios significativos para los usuarios de CPAP, especialmente en condiciones de baja humedad ambiental.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-16-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-16-600x600.jpg'], true, 'humidx', 0, 0, '[]'::jsonb, 'HumidX', 'HumidX is a component designed specifically for ResMed CPAP therapy devices, such as the AirMini, which offers integrated humidification to improve...', 'HumidX is a component designed specifically for ResMed CPAP therapy devices, such as the AirMini, which offers integrated humidification to improve respiratory comfort during sleep. This small heat and moisture exchanger fits directly inside the mask connector, offering significant benefits for CPAP users, especially in conditions of baja ambient humidity.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Kit Remplazo De Accesorios Resmed S10', 'Accesorios de Sueño', 2489.0, 2489.0, 'Este kit incluye una variedad de accesorios esenciales que se desgastan con el tiempo o necesitan ser reemplazados periódicamente para garantizar u...', 'Este kit incluye una variedad de accesorios esenciales que se desgastan con el tiempo o necesitan ser reemplazados periódicamente para garantizar un funcionamiento óptimo del equipo CPAP, diseñados para los dispositivos de la serie ResMed AirSense 10 y AirCurve 10, que son máquinas de terapia de presión positiva en la vía aérea (CPAP y BiPAP).', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-11-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-11-600x600.jpg'], true, 'kit-remplazo-de-accesorios-resmed-s10', 0, 0, '[]'::jsonb, 'ResMed S10 Accessory Replacement Kit', 'This kit includes a variety of essential accessories that wear out over time or need to be replaced periodically to ensure optimal operation of the...', 'This kit includes a variety of essential accessories that wear out over time or need to be replaced periodically to ensure optimal operation of the CPAP equipment, designed for ResMed AirSense 10 and AirCurve 10 series devices, which are positive airway pressure therapy machines (CPAP and BiPAP).');
