INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Mascarilla Airtouch N20', 'Terapia de Sueño', 5207.0, 5207.0, 'Su diseño incluye una almohadilla de espuma viscoelástica UltraSoft™, que se adapta perfectamente a los contornos faciales, minimizando las marcas ...', 'Su diseño incluye una almohadilla de espuma viscoelástica UltraSoft™, que se adapta perfectamente a los contornos faciales, minimizando las marcas y proporcionando una experiencia de uso agradable.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-23-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-23-600x600.jpg'], true, 'mascarilla-airtouch-n20', 0, 0, '[]'::jsonb, 'AirTouch N20 Mask', 'Its design includes an UltraSoft™ memory foam cushion, which perfectly adapts to facial contours, minimizing marks and providing a pleasant wearing...', 'Its design includes an UltraSoft™ memory foam cushion, which perfectly adapts to facial contours, minimizing marks and providing a pleasant wearing experience.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Mascarilla Kn95', 'Protección Personal', 620.0, 620.0, 'Mascarilla de filtrado facial que cumple con los estándares de filtración de partículas establecidos por China, similares a los estándares de N95 e...', 'Mascarilla de filtrado facial que cumple con los estándares de filtración de partículas establecidos por China, similares a los estándares de N95 en los Estados Unidos. Están diseñadas para ofrecer una protección efectiva contra partículas en el aire, incluidos aerosoles y gotículas que pueden contener virus y otros patógenos', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-06-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-06-600x600.jpg'], true, 'mascarilla-kn95', 0, 0, '[]'::jsonb, 'KN95 Mask', 'Facial filtering mask that meets particle filtration standards established by China, similar to N95 standards in the United States. They are design...', 'Facial filtering mask that meets particle filtration standards established by China, similar to N95 standards in the United States. They are designed to offer effective protection against airborne particles, including aerosols and droplets that may contain viruses and other pathogens.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Oximetro P Dedo C 3 Modos De Visualizacion', 'Monitoreo', 420.0, 420.0, 'Pantalla anti raspaduras con diseño tipo espejo avanzada tecnología de spo2 con lectura de índice de perfusión pi 6 modos de pantalla para valores ...', 'Pantalla anti raspaduras con diseño tipo espejo avanzada tecnología de spo2 con lectura de índice de perfusión pi 6 modos de pantalla para valores de spo2, pi, fc, onda de pulso, barra gráfica menú y comandos amigables ajuste de brillo y memorias fuente sistema anti interferencia baja perfusión 03%. Bajo consumo de energía función de auto apagado sonido de pulso en tiempo real.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-31-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-31-600x600.jpg'], true, 'oximetro-p-dedo-c-3-modos-de-visualizacion', 0, 0, '[]'::jsonb, 'Finger Oximeter with 3 Display Modes', 'Anti-scratch screen with advanced mirror-type design, advanced SpO2 technology with PI (perfusion index) reading, 6 display modes for SpO2 values, ...', 'Anti-scratch screen with advanced mirror-type design, advanced SpO2 technology with PI (perfusion index) reading, 6 display modes for SpO2 values, PI, HR (heart rate), pulse wave, graphic bar, friendly menu and commands, brightness adjustment and memories, anti-interference source system, low perfusion 0.3%. Low energy consumption, auto-off function, real-time pulse sound.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Pila Inogen G3 4 5 Horas', 'Oxigenoterapia', 15675.0, 15675.0, 'Esta batería proporciona hasta 4.5 horas de uso continuo, ofreciendo a los usuarios mayor libertad y movilidad sin preocuparse por la necesidad de ...', 'Esta batería proporciona hasta 4.5 horas de uso continuo, ofreciendo a los usuarios mayor libertad y movilidad sin preocuparse por la necesidad de recargar con frecuencia. Es una batería de reemplazo o adicional para el concentrador de oxígeno portátil Inogen One G3, diseñada para proporcionar energía portátil y permitir el uso continuo del dispositivo durante períodos prolongados sin necesidad de conexión a una fuente de alimentación fija.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-24-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-24-600x600.jpg'], true, 'pila-inogen-g3-4-5-horas', 0, 0, '[]'::jsonb, 'Inogen G3 Battery 4.5 Hours', 'This battery provides up to 4.5 hours of continuous use, offering users greater freedom and mobility without worrying about the need to recharge fr...', 'This battery provides up to 4.5 hours of continuous use, offering users greater freedom and mobility without worrying about the need to recharge frequently. It is a replacement or additional battery for the Inogen One G3 portable oxygen concentrator, designed to provide portable power and allow continuous use of the device for extended periods without needing a connection to a fixed power source.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Resucitador Manual 1 Pza', 'Emergencias', 502.0, 502.0, 'Resucitador manual con niveles más altos de suministro de oxígeno y componentes preinstalados en envases de rápida apertura. Proporciona cuidado rá...', 'Resucitador manual con niveles más altos de suministro de oxígeno y componentes preinstalados en envases de rápida apertura. Proporciona cuidado rápido y eficaz en las situaciones más difíciles. MARCA: flexicare', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-32-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-32-600x600.jpg'], true, 'resucitador-manual-1-pza', 0, 0, '[]'::jsonb, 'Manual Resuscitator 1 Pc', 'Manual resuscitator with higher levels of oxygen supply and pre-installed components in quick-opening packaging. Provides fast and effective care i...', 'Manual resuscitator with higher levels of oxygen supply and pre-installed components in quick-opening packaging. Provides fast and effective care in the most difficult situations. BRAND: flexicare.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Rollos De Impresion Para Microlab', 'Consumibles', 1326.0, 1326.0, 'Estos rollos de impresión están diseñados específicamente para imprimir los resultados de las pruebas realizadas con el MicroLab en forma de gráfic...', 'Estos rollos de impresión están diseñados específicamente para imprimir los resultados de las pruebas realizadas con el MicroLab en forma de gráficos y datos numéricos. Estos rollos son esenciales para registrar y documentar los datos obtenidos durante las pruebas de función pulmonar y otros análisis respiratorios.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-05-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-05-600x600.jpg'], true, 'rollos-de-impresion-para-microlab', 0, 0, '[]'::jsonb, 'MicroLab Printing Rolls', 'These printing rolls are specifically designed to print the results of tests performed with the MicroLab in the form of charts and numerical data. ...', 'These printing rolls are specifically designed to print the results of tests performed with the MicroLab in the form of charts and numerical data. These rolls are essential for recording and documenting the data obtained during lung function tests and other respiratory analyses.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Sistema De Control De Temperatura P3', 'Cuidado Neonatal', 439690.0, 439690.0, 'Enfriamiento rápido mediante el uso de mantas de enfriamiento para alcanzar una temperatura corporal central de 33 °C hasta 34 °C en el lapso de 2 ...', 'Enfriamiento rápido mediante el uso de mantas de enfriamiento para alcanzar una temperatura corporal central de 33 °C hasta 34 °C en el lapso de 2 horas. Mantenimiento: Mantiene la temperatura corporal central de los recién nacidos a 33,5 °C hasta 34 °C durante 72 horas. Recalentamiento: Recupera la temperatura corporal central de los recién nacidos hasta 37 °C a 0,5 °C / 2 horas con mantenimiento de normotermia.', 'https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-41-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-41-600x600.jpg'], true, 'sistema-de-control-de-temperatura-p3', 0, 0, '[]'::jsonb, 'P3 Temperature Control System', 'Rapid cooling using cooling blankets to reach a core body temperature of 33°C to 34°C within 2 hours. Maintenance: Maintains the core body temperat...', 'Rapid cooling using cooling blankets to reach a core body temperature of 33°C to 34°C within 2 hours. Maintenance: Maintains the core body temperature of newborns at 33.5°C to 34°C for 72 hours. Reheating: Recovers the core body temperature of newborns to 37°C at 0.5°C / 2 hours with maintenance of normothermia.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Sistema De Reanimacion Con Pieza En T Bq70', 'Cuidado Neonatal', 58500.0, 58500.0, 'Mezcla de aire y oxígeno, succión de presión negativa, control de presión abierta, Reanimación, oxigenoterapia, monitorización de la presión de las...', 'Mezcla de aire y oxígeno, succión de presión negativa, control de presión abierta, Reanimación, oxigenoterapia, monitorización de la presión de las vías respiratorias, control de la presión máxima, monitoreo de presión negativa, alarma mecánica.', 'https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-40-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-40-600x600.jpg'], true, 'sistema-de-reanimacion-con-pieza-en-t-bq70', 0, 0, '[]'::jsonb, 'T-Piece Resuscitation System BQ70', 'Air and oxygen mixture, negative pressure suction, open pressure control, Resuscitation, oxygen therapy, airway pressure monitoring, maximum pressu...', 'Air and oxygen mixture, negative pressure suction, open pressure control, Resuscitation, oxygen therapy, airway pressure monitoring, maximum pressure control, negative pressure monitoring, mechanical alarm.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Sujetador De Mandibula', 'Accesorios de Sueño', 899.0, 899.0, 'Está diseñado para mantener la mandíbula en una posición específica durante el sueño, lo que ayuda a mantener abiertas las vías respiratorias super...', 'Está diseñado para mantener la mandíbula en una posición específica durante el sueño, lo que ayuda a mantener abiertas las vías respiratorias superiores y a prevenir la obstrucción que puede causar apnea o ronquidos. Estos sujetadores están destinados a promover una mejor respiración al mantener la vía aérea abierta y reducir la obstrucción durante la noche.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-12-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-12-600x600.jpg'], true, 'sujetador-de-mandibula', 0, 0, '[]'::jsonb, 'Jaw Strap', 'It is designed to hold the jaw in a specific position during sleep, which helps keep the upper airways open and prevent the obstruction that can ca...', 'It is designed to hold the jaw in a specific position during sleep, which helps keep the upper airways open and prevent the obstruction that can cause apnea or snoring. These straps are intended to promote better breathing by keeping the airway open and reducing obstruction during the night.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Termometro Infrarrojo Yuwell Yt 1', 'Monitoreo', 3127.0, 3127.0, 'Dispositivo de medición de temperatura sin contacto, diseñado para proporcionar lecturas rápidas y precisas de la temperatura corporal. Este tipo d...', 'Dispositivo de medición de temperatura sin contacto, diseñado para proporcionar lecturas rápidas y precisas de la temperatura corporal. Este tipo de termómetros son ideales para uso doméstico y profesional, especialmente en entornos donde se requiere medir la temperatura de manera rápida y sin contacto directo con la piel.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-04-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-04-600x600.jpg'], true, 'termometro-infrarrojo-yuwell-yt-1', 0, 0, '[]'::jsonb, 'Yuwell YT-1 Infrared Thermometer', 'Non-contact temperature measurement device, designed to provide fast and accurate body temperature readings. These types of thermometers are ideal ...', 'Non-contact temperature measurement device, designed to provide fast and accurate body temperature readings. These types of thermometers are ideal for domestic and professional use, especially in environments where temperature measurement is required quickly and without direct contact with the skin.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Tridiodo Laser Mini', 'Láser Médico', 220000.0, 220000.0, 'Barra Laser americana, todo tipo de piel, todo tipo de vello, tratamiento rápido, 10 disparos/s, 1200W, fácil uso', 'Barra Laser americana, todo tipo de piel, todo tipo de vello, tratamiento rápido, 10 disparos/s, 1200W, fácil uso', 'https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-49-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/08/productos-prime-health-49-600x600.jpg'], true, 'tridiodo-laser-mini', 0, 0, '[]'::jsonb, 'Tridiode Laser Mini', 'American Laser Bar, all skin types, all hair types, fast treatment, 10 shots/s, 1200W, easy use.', 'American Laser Bar, all skin types, all hair types, fast treatment, 10 shots/s, 1200W, easy use.');
INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Vaso Borboteador Para Concentrador', 'Oxigenoterapia', 463.0, 463.0, 'Componente utilizado en algunos sistemas de suministro de oxígeno, como concentradores de oxígeno, para humidificar y filtrar el oxígeno que se sum...', 'Componente utilizado en algunos sistemas de suministro de oxígeno, como concentradores de oxígeno, para humidificar y filtrar el oxígeno que se suministra al paciente. Este dispositivo se utiliza para humidificar el oxígeno antes de que se entregue al paciente, asegurando que el aire que se inhala esté adecuadamente humidificado y sea más cómodo para los pulmones y las vías respiratorias.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-03-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-03-600x600.jpg'], true, 'vaso-borboteador-para-concentrador', 0, 0, '[]'::jsonb, 'Concentrator Bubble Humidifier Jar', 'Component used in some oxygen supply systems, such as oxygen concentrators, to humidify and filter the oxygen supplied to the patient. This device ...', 'Component used in some oxygen supply systems, such as oxygen concentrators, to humidify and filter the oxygen supplied to the patient. This device is used to humidify the oxygen before it is delivered to the patient, ensuring that the inhaled air is adequately humidified and more comfortable for the lungs and airways.');
