INSERT INTO public.distribucionmedica_products (name, category, price, "originalPrice", description, "longDescription", image, images, "inStock", sku, rating, reviews, specifications, name_english, description_english, "longDescription_english") VALUES ('Virtuclean 2 0', 'Desinfección', 9560.0, 9560.0, 'VirtuCLEAN 2.0 Dispositivo de limpieza automática de CPAP diseñado para facilitar el proceso de limpieza y desinfección de equipos de terapia de ap...', 'VirtuCLEAN 2.0 Dispositivo de limpieza automática de CPAP diseñado para facilitar el proceso de limpieza y desinfección de equipos de terapia de apnea del sueño, como máscaras, tubos y humidificadores. Ofrece una solución conveniente y efectiva para mantener estos dispositivos libres de gérmenes y bacterias, promoviendo así una terapia más higiénica y segura.', 'https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-18-600x600.jpg', ARRAY['https://prime-health.mx/wp-content/uploads/2024/06/productos-prime-health-18-600x600.jpg'], true, 'virtuclean-2-0', 0, 0, '[]'::jsonb, 'VirtuCLEAN 2.0', 'VirtuCLEAN 2.0 Automatic CPAP cleaning device designed to facilitate the cleaning and disinfection process of sleep apnea therapy equipment, such a...', 'VirtuCLEAN 2.0 Automatic CPAP cleaning device designed to facilitate the cleaning and disinfection process of sleep apnea therapy equipment, such as masks, tubes, and humidifiers. It offers a convenient and effective solution for keeping these devices free of germs and bacteria, thus promoting a more hygienic and safer therapy.');